const DAY_MS = 86_400_000;
function utcDate(value) {
    return Date.parse(`${value}T00:00:00.000Z`);
}
export function lifecycleFor(model, at = new Date(), criticalDays = 90) {
    const today = Date.UTC(at.getUTCFullYear(), at.getUTCMonth(), at.getUTCDate());
    const shutdown = utcDate(model.shutdownAt);
    const daysUntilShutdown = Math.ceil((shutdown - today) / DAY_MS);
    let state = 'deprecated';
    if (daysUntilShutdown <= 0)
        state = 'retired';
    else if (daysUntilShutdown <= criticalDays)
        state = 'critical';
    return { ...model, state, daysUntilShutdown };
}
export function shouldFail(report, failOn) {
    if (failOn === 'never')
        return false;
    if (failOn === 'retired')
        return report.findings.some((finding) => finding.model.state === 'retired');
    return report.findings.length > 0;
}
export function stateRank(state) {
    return state === 'retired' ? 3 : state === 'critical' ? 2 : 1;
}
